external_knowledge:
- "golden treasure chest of 5000" metaphorically refers to a total spending amount of 5000;
- "pledged their gold" is a metaphor for making purchases or placing orders;
- "loyal voyagers" refers to customers who have spent a significant amount;
- "frequency of visits" refers to the number of orders placed by the customers.

sql:
SELECT SUM(total_price) 
FROM orders 
WHERE order_status = 'F' AND region = 'Europe';

SELECT clerk_name 
FROM clerk_info 
WHERE clerk_id = (SELECT clerk FROM orders WHERE order_key = 1);

SELECT clerk_id, clerk_name
FROM clerk_info
WHERE department = 'Sales';

SELECT order_key, order_status, total_price, order_date
FROM orders
WHERE clerk = 'C0101' AND product_id = 'P001';

SELECT COUNT(*) AS open_orders
FROM orders
WHERE order_status = 'O' AND strftime('%m', order_date) = '04';

SELECT order_key 
FROM order_returns
WHERE return_status = 'Completed';
